  const [advice, setAdvice] = useState(null);

  useEffect(() => {
    if (query) {
      const lowerCaseQuery = query.toLowerCase();
      
      // Fetch Health Advice
      axios.get(`${base_url}health-advice/recommendations?query=${query}`)
        .then(res => setAdvice(res.data))
        .catch(err => console.error("Error fetching health advice", err));

      const results = data.filter((product) => {
        return (
          product.title.toLowerCase().includes(lowerCaseQuery) ||
          product.brand.toLowerCase().includes(lowerCaseQuery) ||
          product.category.toLowerCase().includes(lowerCaseQuery) ||
          product.description.toLowerCase().includes(lowerCaseQuery) ||
          product.subcategory.toLowerCase().includes(lowerCaseQuery) ||
          (product.tags && product.tags.toLowerCase().includes(lowerCaseQuery))
        );
      });
      setFilteredProducts(results);
    }
  }, [query, data]);
